CREATE TABLE public.eventos_financeiros (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, mes_referencia TEXT NOT NULL, fornecedor_id UUID REFERENCES public.fornecedores(id) ON DELETE SET NULL, categoria TEXT NOT NULL, descricao TEXT, valor_previsto NUMERIC(14,2), valor_efetivo NUMERIC(14,2), data_vencimento DATE, data_pagamento DATE, origem TEXT NOT NULL DEFAULT 'manual', status_documental TEXT NOT NULL DEFAULT 'pendente', prestacao_snapshot_id UUID, metadata JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_eventos_mes ON public.eventos_financeiros(mes_referencia); CREATE INDEX idx_eventos_fornecedor ON public.eventos_financeiros(fornecedor_id); CREATE INDEX idx_eventos_categoria ON public.eventos_financeiros(categoria); ALTER TABLE public.eventos_financeiros ENABLE ROW LEVEL SECURITY; CREATE POLICY "auth_view_eventos" ON public.eventos_financeiros FOR SELECT TO authenticated USING (true); CREATE POLICY "auth_insert_eventos" ON public.eventos_financeiros FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY "auth_update_eventos" ON public.eventos_financeiros FOR UPDATE TO authenticated USING (true); CREATE POLICY "auth_delete_eventos" ON public.eventos_financeiros FOR DELETE TO authenticated USING (true); CREATE OR REPLACE FUNCTION public.set_updated_at() RETURNS TRIGGER LANGUAGE plpgsql SET search_path = public AS $$ BEGIN NEW.updated_at = now(); RETURN NEW; END $$; CREATE TRIGGER trg_eventos_updated_at BEFORE UPDATE ON public.eventos_financeiros FOR EACH ROW EXECUTE FUNCTION public.set_updated_at(); CREATE TABLE public.documentos_anexos (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, evento_id UUID REFERENCES public.eventos_financeiros(id) ON DELETE CASCADE, tipo TEXT NOT NULL, arquivo_url TEXT, arquivo_hash TEXT, cnpj_extraido TEXT, valor_extraido NUMERIC(14,2), data_extraida DATE, numero_extraido TEXT, origem TEXT NOT NULL DEFAULT 'manual', gmail_message_id TEXT, metadata JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_docs_evento ON public.documentos_anexos(evento_id); CREATE INDEX idx_docs_hash ON public.documentos_anexos(arquivo_hash); CREATE INDEX idx_docs_cnpj ON public.documentos_anexos(cnpj_extraido); ALTER TABLE public.documentos_anexos ENABLE ROW LEVEL SECURITY; CREATE POLICY "auth_view_docs" ON public.documentos_anexos FOR SELECT TO authenticated USING (true); CREATE POLICY "auth_insert_docs" ON public.documentos_anexos FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY "auth_update_docs" ON public.documentos_anexos FOR UPDATE TO authenticated USING (true); CREATE POLICY "auth_delete_docs" ON public.documentos_anexos FOR DELETE TO authenticated USING (true);